import { useState, useEffect } from "react";
import axios from "axios";
import AIChat from "./AIChat";

function App() {
  const [isLogin, setIsLogin] = useState(false);
  const [isRegister, setIsRegister] = useState(false);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const [courses, setCourses] = useState([]);
  const [enrolled, setEnrolled] = useState([]);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [progress, setProgress] = useState({});

  const handleAuth = async () => {
  try {
    const url = isRegister
      ? "http://localhost:5000/register"
      : "http://localhost:5000/login";

    const res = await axios.post(url, { email, password });

    console.log("SUCCESS:", res.data);

    setIsLogin(true);
  } catch (err) {
    console.error("ERROR:", err);

    alert("Backend not working ❌\nCheck if server is running");
  }
};

  useEffect(() => {
    if (isLogin) {
      axios.get("http://localhost:5000/courses").then(res => setCourses(res.data));
      axios.get("http://localhost:5000/enrolled").then(res => setEnrolled(res.data));
    }
  }, [isLogin]);

  const handleEnroll = async (course) => {
    await axios.post("http://localhost:5000/enroll", { course });
    const res = await axios.get("http://localhost:5000/enrolled");
    setEnrolled(res.data);
  };

  const markComplete = (id) => {
    setProgress({ ...progress, [id]: 100 });
  };

  // 🔐 LOGIN PAGE
  if (!isLogin) {
    return (
      <div style={styles.authContainer}>
        <div style={styles.authBox}>
          <h1>Skillify</h1>
          <h3>{isRegister ? "Create Account" : "Login"}</h3>

          <input
            style={styles.input}
            placeholder="Email"
            onChange={(e) => setEmail(e.target.value)}
          />
          <input
            style={styles.input}
            type="password"
            placeholder="Password"
            onChange={(e) => setPassword(e.target.value)}
          />

          <button style={styles.primaryBtn} onClick={handleAuth}>
            {isRegister ? "Register" : "Login"}
          </button>

          <p onClick={() => setIsRegister(!isRegister)} style={styles.link}>
            {isRegister ? "Already have account? Login" : "Create account"}
          </p>
        </div>
      </div>
    );
  }

  // 🎥 VIDEO PAGE
  if (selectedCourse) {
    return (
      <div style={styles.videoPage}>
        <h2>{selectedCourse.title}</h2>

        <iframe
          width="900"
          height="450"
          src={selectedCourse.video}
          title="video"
          style={styles.video}
        />

        <br /><br />

        <button
          style={styles.primaryBtn}
          onClick={() => markComplete(selectedCourse.id)}
        >
          Mark Complete ✅
        </button>

        <h3>Progress: {progress[selectedCourse.id] || 0}%</h3>

        <button style={styles.secondaryBtn} onClick={() => setSelectedCourse(null)}>
          ⬅ Back
        </button>
      </div>
    );
  }

  // 📊 DASHBOARD
  return (
    <div>
      {/* 🔷 NAVBAR */}
      <div style={styles.navbar}>
        <h2>Skillify</h2>

        <input style={styles.search} placeholder="Search courses..." />

        <button style={styles.logoutTop} onClick={() => setIsLogin(false)}>
          Logout
        </button>
      </div>

      <div style={styles.app}>
        {/* SIDEBAR */}
        <div style={styles.sidebar}>
          <h3>My Courses</h3>

          {enrolled.map((c) => (
            <div
              key={c.id}
              style={styles.sidebarItem}
              onClick={() => setSelectedCourse(c)}
            >
              {c.title}
            </div>
          ))}

          <button style={styles.logoutBtn} onClick={() => setIsLogin(false)}>
            Logout 🚪
          </button>
        </div>

        {/* MAIN */}
        <div style={styles.content}>
          <h1>Explore Courses</h1>

          <div style={styles.grid}>
            {courses.map((course) => {
              const isEnrolled = enrolled.find(c => c.id === course.id);

              return (
                <div key={course.id} style={styles.card}>
                  <img src={course.image} style={styles.image} alt="course" />

                  <div style={{ padding: "15px" }}>
                    <h3>{course.title}</h3>
                    <p>{course.description}</p>

                    <p>⭐ 4.5 | 👨‍🎓 10k students</p>
                    <p style={{ color: "blue" }}>₹499</p>

                    {!isEnrolled ? (
                      <button
                        style={styles.primaryBtn}
                        onClick={() => handleEnroll(course)}
                      >
                        Enroll
                      </button>
                    ) : (
                      <>
                        <button style={styles.successBtn}>
                          Enrolled ✅
                        </button>

                        <br /><br />

                        <button
                          style={styles.secondaryBtn}
                          onClick={() => setSelectedCourse(course)}
                        >
                          Continue ▶
                        </button>

                        {/* 📊 PROGRESS */}
                        <div style={styles.progressBar}>
                          <div
                            style={{
                              ...styles.progressFill,
                              width: `${progress[course.id] || 0}%`,
                            }}
                          />
                        </div>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>

          {/* 🤖 AI CHAT */}
          <AIChat />
        </div>
      </div>
    </div>
  );
}

// 🎨 STYLES
const styles = {
  navbar: {
    display: "flex",
    justifyContent: "space-between",
    padding: "15px",
    background: "rgb(28, 31, 29)",
    color: "white",
  },
  search: {
    width: "300px",
    padding: "8px",
  },
  logoutTop: {
    background: "red",
    color: "white",
    border: "none",
    padding: "8px 15px",
  },

  authContainer: {
    height: "100vh",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    background: "linear-gradient(135deg,#667eea,#764ba2)",
  },
  authBox: {
    background: "white",
    padding: "40px",
    borderRadius: "15px",
    textAlign: "center",
  },

  input: {
    display: "block",
    margin: "10px auto",
    padding: "10px",
    width: "250px",
  },

  primaryBtn: {
    background: "rgb(255, 99, 156)",
    color: "white",
    padding: "10px",
    border: "none",
  },
  secondaryBtn: {
    background: "#444",
    color: "white",
    padding: "8px",
    border: "none",
  },
  successBtn: {
    background: "green",
    color: "white",
    padding: "8px",
    border: "none",
  },

  app: { display: "flex" },

  sidebar: {
    width: "220px",
    background: "#2d2f31",
    color: "white",
    padding: "20px",
    height: "100vh",
  },
  sidebarItem: {
    marginTop: "10px",
    cursor: "pointer",
  },

  logoutBtn: {
    marginTop: "30px",
    width: "100%",
    background: "red",
    color: "white",
    padding: "10px",
    border: "none",
  },

  content: {
    flex: 1,
    padding: "20px",
    background: "hsl(270, 79%, 11%)",
  },

  grid: {
    display: "flex",
    gap: "20px",
    flexWrap: "wrap",
  },

  card: {
    width: "260px",
    background: "white",
    boxShadow: "0 5px 10px rgba(0,0,0,0.1)",
  },

  image: {
    width: "100%",
    height: "150px",
    objectFit: "contain",
    background: "hsl(36, 60%, 38%)",
  },

  progressBar: {
    width: "100%",
    height: "6px",
    background: "#ddd",
    marginTop: "10px",
  },

  progressFill: {
    height: "100%",
    background: "green",
  },

  videoPage: {
    textAlign: "center",
    padding: "40px",
  },

  video: {
    borderRadius: "10px",
  },

  link: { color: "green", cursor: "pointer" },
};

export default App;
